const item = $input.first();
const raw = item.json.output || "";
const body = raw
  .replace(/^#{1,3} (.+)$/gm, '*$1*')
  .replace(/\*\*(.+?)\*\*/g, '*$1*')
  .replace(/^---+$/gm, '')
  .replace(/^─+$/gm, '')
  .replace(/^\d+\. (.+)$/gm, '• $1')
  .replace(/^   - (.+)$/gm, '    ◦ $1')
  .replace(/^- (.+)$/gm, '• $1')
  .replace(/\n{3,}/g, '\n\n')
  .replace(/\*\*(.+?)\*\*/g, '*$1*')
  .trim();

const footer = `\n\n_🤖 AI-generated assistant. For official details, please consult the Contractor Services._`;

// Sanitize for safe JSON embedding
const slackMessage = `${body}${footer}`
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t');

return [{ json: { slackMessage } }];

const raw = $input.first().json.output?.trim() || "";

// Strip markdown code fences if present
const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let status = "OFF_TOPIC";
let content = cleaned;

try {
  const parsed = JSON.parse(cleaned);
  status = parsed.status?.trim() || "OFF_TOPIC";
  content = parsed.content?.trim() || cleaned;
} catch (e) {
  const knownFiles = [
    "[Attendance - Payroll] Clocking In",
    "[Attendance - Payroll] Clocking Out",
    "[Attendance - Payroll] Filing Attendance Disputes",
    "[Attendance - Payroll] Logging Activities",
    "[Contractor / Contractor Services] Nomenclature for Independent Contractors",
    "[Contractor / VA Scheduling - Operations] Change Schedule Requests",
    "[Contractor / VA Scheduling - Operations] Overtime Requests",
    "[Time Off / Leaves - Contractor Services] PTO Requests",
    "[User Management / Contractor Services, Department Heads] Approving Attendance Requests",
    "[User Management / Contractor Services] Adding New Users to SV Portal",
    "[User Management / DevOps] SV Portal Pages and Features"
  ];

  if (knownFiles.some(f => cleaned.includes(f))) {
    status = "FOUND";
    content = knownFiles.find(f => cleaned.includes(f));
  } else if (cleaned.startsWith("REPLY:")) {
    content = cleaned.replace(/^REPLY:\s*/, "").trim();
  }
}

// ✅ SANITIZE content for safe JSON embedding in Slack blocks
const sanitized = content
  .replace(/\\/g, '\\\\')   // escape backslashes first
  .replace(/"/g, '\\"')      // escape double quotes
  .replace(/\n/g, '\\n')     // escape newlines
  .replace(/\r/g, '\\r')     // escape carriage returns
  .replace(/\t/g, '\\t');    // escape tabs

return [{ json: { status, content: sanitized } }];

