// 1. Parse the incoming Slack payload
const payload = JSON.parse($input.first().json.body.payload);

// 2. Get the action details
const action = payload.actions[0];


// ✅ Guard: STOP execution if this isn't the Airtable feedback button click
if (action.action_id !== 'open_airtable_feedback') {
  // Returning an empty array tells n8n there is no data to process, 
  // effectively stopping the workflow here.
  return []; 
}

// 3. Grab the user, channel, and message timestamps
const userId = payload.user.id;
const channelId = payload.channel.id;
const messageTs = payload.container.message_ts;

// Grab the thread timestamp (this acts as your original anchor_ts)
// Fallback to messageTs if the message isn't part of a thread
const threadTs = payload.container.thread_ts || messageTs;

// 4. Output
return [{
  json: {
    feedback: "airtable_form_opened", 
    anchor_ts: threadTs,
    user_id: userId,
    channel_id: channelId,
    click_ts: messageTs,
    original_text: payload.message.blocks[0].text.text
  }
}];

const data = $input.first().json;
const files = data.files || [];
const names = files.map(function(f) {
  if (f && typeof f === 'object') return f.name || '';
  return String(f || '');
}).filter(function(n) { return n.length > 0; });
return [{ json: { files: names } }];

// ─── Eval Pass/Fail Summary ───────────────────────────────────────────────────
//
// Scoring:
//   Correctness  1–5  (from Evaluation1)
//   Helpfulness  1–5  (from Evaluation: Helpfulness)
//   Categorization 0 or 1 — INSTANT FAIL if 0
//
// Total = Correctness + Helpfulness  (max 10)
// PASS requires: categorization === 1  AND  total >= PASS_THRESHOLD
//
const PASS_THRESHOLD = 7; // out of 10 (70%) — adjust here if needed

// Pull scores — use .first().json for "Run Once for All Items" mode
const correctnessRaw    = $('Evaluation1').first().json;
const helpfulnessRaw    = $('Evaluation: Helpfulness').first().json;
const categorizationRaw = $('Categorization').first().json;

const correctnessScore    = correctnessRaw?.Correctness    ?? correctnessRaw?.correctness    ?? null;
const helpfulnessScore    = helpfulnessRaw?.helpfulness    ?? helpfulnessRaw?.Helpfulness    ?? null;
const categorizationScore = categorizationRaw?.Categorization ?? categorizationRaw?.categorization ?? null;

// Instant fail if categorization is wrong
const categorizationPassed = categorizationScore === 1;

// Total of numeric scores
const total    = (correctnessScore ?? 0) + (helpfulnessScore ?? 0);
const maxTotal = 10;

const scorePassed   = total >= PASS_THRESHOLD;
const overallPassed = categorizationPassed && scorePassed;

// Build failure reasons
const failureReasons = [];
if (!categorizationPassed) {
  failureReasons.push(
    `INSTANT FAIL: Categorization mismatch (score: ${categorizationScore}) — actual_status did not match expected_status`
  );
}
if (!scorePassed) {
  failureReasons.push(
    `Total score ${total}/${maxTotal} is below pass threshold of ${PASS_THRESHOLD}/${maxTotal} — Correctness: ${correctnessScore}/5, Helpfulness: ${helpfulnessScore}/5`
  );
}
if (correctnessScore === null)    failureReasons.push('Correctness score unavailable');
if (helpfulnessScore === null)    failureReasons.push('Helpfulness score unavailable');
if (categorizationScore === null) failureReasons.push('Categorization score unavailable');

return [{
  json: {
    pass_fail: overallPassed ? 'PASS' : 'FAIL',
    total_score: total,
    max_score: maxTotal,
    pass_threshold: PASS_THRESHOLD,
    scores: {
      correctness:    correctnessScore,
      helpfulness:    helpfulnessScore,
      categorization: categorizationScore
    },
    failure_reasons: failureReasons,
    summary: overallPassed
      ? `PASS — Total: ${total}/${maxTotal}, Categorization: matched`
      : `FAIL — ${failureReasons.join(' | ')}`
  }
}];

// Increment retry counter.
// Returns [] (stops) when max 3 retries exhausted.
const RETRY_LIMIT = 3;

const prev = $input.first().json;
const retryCount = (prev._retry_count ?? 0) + 1;
const failedDoc  = prev.content ?? prev._failed_doc ?? '';

if (retryCount > RETRY_LIMIT) {
  // Max retries exceeded — stop the loop silently
  return [];
}

// Pass data back to Classifier with retry context
return [{
  json: {
    ...prev,
    _retry_count: retryCount,
    _failed_doc: failedDoc
  }
}];

const items = $input.all();
const fileMap = {};

for (const item of items) {
  // Both Google Docs and Drive Download paths may produce items
  // Google Docs path: item.json.id, item.json.body (content as text)
  // Drive Extract path: item.json.id, item.json.text or item.json.data
  const id = item.json.id || item.json.documentId || '';
  const name = item.json.title || item.json.name || item.json.documentId || id || 'Document';

  // Build content string from whatever field the path gives us
  let text = '';
  if (typeof item.json.content === 'string') text = item.json.content;
  else if (typeof item.json.text === 'string') text = item.json.text;
  else if (typeof item.json.data === 'string') text = item.json.data;

  text = text.trim();

  // Keep whichever path gave us more text for this file
  if (!fileMap[id] || text.length > (fileMap[id].content || '').length) {
    fileMap[id] = { name, content: text };
  }
}

const sections = Object.values(fileMap)
  .filter(f => f.content && f.content.replace(/\n/g, '').trim().length > 5)
  .map(f => '=== ' + f.name + ' ===\n' + f.content);

const combinedContent = sections.length > 0
  ? sections.join('\n\n---\n\n')
  : 'No document content could be retrieved.';

return [{ json: { combinedContent } }];

const files = $('Trim Files').first().json.files || [];
const keywordsContent = $('Fetch Keywords Doc').first().json.content || '';
const retryData = {};

// Pass through any retry metadata from current input
const input = $input.first().json;
if (input._retry_count) retryData._retry_count = input._retry_count;
if (input._failed_doc) retryData._failed_doc = input._failed_doc;

return [{ json: { files, keywordsContent, ...retryData } }];

// 1. Parse the incoming Slack payload
const payload = JSON.parse($input.first().json.body.payload);

// 2. Get the value — may be undefined if it's not a feedback button
const rawValue = payload.actions[0].value;

// ✅ Guard: skip if this isn't a feedback button click
if (!rawValue || !rawValue.includes('_')) {
  return [{
    json: {
      skipped: true,
      reason: 'Not a feedback button click',
      action_id: payload.actions[0].action_id
    }
  }];
}

// 3. Split the value (e.g., "helpful_1773338337.652549")
const splitValue = rawValue.split('_');
const feedbackType = splitValue[0];
const originalTs = splitValue[1];

// 4. Grab the user, channel, and message timestamps
const userId = payload.user.id;
const channelId = payload.channel.id;
const messageTs = payload.container.message_ts;

// 5. Output
return [{
  json: {
    feedback: feedbackType,
    anchor_ts: originalTs,
    user_id: userId,
    channel_id: channelId,
    click_ts: messageTs,
    original_text: payload.message.blocks[0].text.text
  }
}];
